import React, { useEffect, useState } from "react";
import { StyledPage } from "./styles";
import Layout from "../Layout";

interface PageProps {
  children?: React.ReactNode;
}

const Page: React.FC<PageProps> = ({ children }) => {
  return (
    <>
      <Layout>
        <StyledPage>{children}</StyledPage>
      </Layout>
    </>
  );
};

export default Page;
